import React, { useState, useEffect, useCallback, useRef } from 'react';
import { startVideoGeneration, checkVideoStatus } from '../services/geminiService';
import { addData, getAllData, updateData, deleteData, deductCredits, getUserCredits } from '../services/dbService';
import Spinner from './Spinner';

interface VideoStudioProps {
  onClose: () => void;
  galleryImages: { url: string; file: File | null; prompt: string }[];
  userId: string;
  credits: number;
  onReauth: () => Promise<void>;
}

interface VideoJob {
  id: string;
  operationName?: string;
  status: 'queued' | 'processing' | 'done' | 'error';
  progressMessage: string;
  videoUrl?: string; 
  startTime: number;
  prompt: string;
  mode: string;
  model: string;
}

const PlayIcon = () => <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" /></svg>;
const TrashIcon = () => <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>;
const CloseIcon = () => (
    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
        <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
    </svg>
);
const KeyIcon = () => (
    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
        <path strokeLinecap="round" strokeLinejoin="round" d="M15 7a2 2 0 012 2m-2 4a2 2 0 012 2m-2-4a2 2 0 01-2-2m2 4a2 2 0 01-2 2m5-10a2 2 0 00-2-2H9a2 2 0 00-2 2v3m2 4H7a2 2 0 01-2-2V5a2 2 0 012-2h9a2 2 0 012 2v1" />
    </svg>
);

const VideoStudio: React.FC<VideoStudioProps> = ({ onClose, galleryImages, userId, credits: initialCredits, onReauth }) => {
  const [activeJobs, setActiveJobs] = useState<VideoJob[]>([]);
  const [keyframes, setKeyframes] = useState<{ url: string; file: File }[]>([]);
  const [mode, setMode] = useState<'living' | 'morph' | 'multi'>('living');
  const [selectedModel, setSelectedModel] = useState<'veo-3.1-fast-generate-preview' | 'veo-3.1-generate-preview'>('veo-3.1-fast-generate-preview');
  const [prompt, setPrompt] = useState('');
  const [aspectRatio, setAspectRatio] = useState<'16:9' | '9:16'>('16:9');
  const [isGenerating, setIsGenerating] = useState(false);
  const [currentCredits, setCurrentCredits] = useState(initialCredits);

  const jobsRef = useRef(activeJobs);
  useEffect(() => { jobsRef.current = activeJobs; }, [activeJobs]);

  useEffect(() => {
    const loadData = async () => {
      const [storedJobs, userCredits] = await Promise.all([getAllData('videos', userId), getUserCredits(userId)]);
      setCurrentCredits(userCredits);
      setActiveJobs(storedJobs.map(item => ({
        id: item.id,
        operationName: item.operationName,
        status: item.status,
        progressMessage: item.status === 'done' ? 'Ready' : 'Rendering...',
        videoUrl: item.url,
        startTime: item.createdAt,
        prompt: item.prompt,
        mode: item.mode || 'VEO',
        model: item.model || 'veo-3.1'
      })));
    };
    loadData();
  }, [userId]);

  const pollJobs = useCallback(async () => {
    const processing = jobsRef.current.filter(j => j.status === 'processing' || j.status === 'queued');
    if (processing.length === 0) return;

    for (const job of processing) {
      if (!job.operationName) continue;
      try {
        const status = await checkVideoStatus({ name: job.operationName });
        if (status.done) {
          const uri = status.response?.generatedVideos?.[0]?.video?.uri;
          if (uri) {
            const key = process.env.API_KEY || '';
            const resp = await fetch(`${uri}&key=${key}`);
            const blob = await resp.blob();
            const url = URL.createObjectURL(blob);

            setActiveJobs(prev => prev.map(j => j.id === job.id ? { ...j, status: 'done', videoUrl: url, progressMessage: 'Done' } : j));
            await updateData('videos', job.id, { status: 'done', url });
          } else if (status.error) {
             const errorMsg = status.error.message || 'Unknown Error';
             if (errorMsg.includes("Requested entity was not found")) {
                setActiveJobs(prev => prev.map(j => j.id === job.id ? { ...j, status: 'error', progressMessage: 'Auth Required' } : j));
                onReauth();
             } else {
                setActiveJobs(prev => prev.map(j => j.id === job.id ? { ...j, status: 'error', progressMessage: 'Failed' } : j));
             }
             await updateData('videos', job.id, { status: 'error' });
          }
        }
      } catch (e: any) { 
        console.error("Polling error for job:", job.id, e);
        if (e.message?.includes("Requested entity was not found")) {
            onReauth();
        }
      }
    }
  }, [onReauth]);

  useEffect(() => {
    const timer = setInterval(pollJobs, 10000);
    return () => clearInterval(timer);
  }, [pollJobs]);

  const handleStartGeneration = async () => {
    if (keyframes.length === 0 || isGenerating) return;
    setIsGenerating(true);
    const cost = selectedModel.includes('fast') ? 5 : 15;
    if (currentCredits < cost && userId !== 'admin') { alert("Insufficient credits."); setIsGenerating(false); return; }

    try {
      const op = await startVideoGeneration({
        prompt: `${mode.toUpperCase()}: ${prompt}`,
        image: keyframes[0].file,
        lastFrame: mode === 'morph' && keyframes.length > 1 ? keyframes[1].file : undefined,
        referenceImages: mode === 'multi' ? keyframes.map(k => k.file) : undefined,
        aspectRatio, resolution: '720p', model: selectedModel
      });

      if (!op.name) throw new Error("Failed to start generation - no operation name returned.");

      await deductCredits(userId, cost);
      setCurrentCredits(prev => prev - cost);

      const newJob: VideoJob = {
        id: `v-${Date.now()}`,
        operationName: op.name,
        status: 'processing',
        progressMessage: 'Initializing...',
        startTime: Date.now(),
        prompt: prompt || 'Architectural View',
        mode: mode.toUpperCase(),
        model: selectedModel
      };

      await addData('videos', { ...newJob, userId, createdAt: newJob.startTime, url: '' });
      setActiveJobs(prev => [newJob, ...prev]);
      setKeyframes([]); setPrompt('');
    } catch (e: any) { 
      console.error("VEO Error:", e);
      if (e.message?.includes("Requested entity was not found")) {
        alert("Video generation requires a paid API key. Please select your key again.");
        await onReauth();
      } else {
        alert(`Generation Error: ${e.message}`);
      }
    } finally { setIsGenerating(false); }
  };

  return (
    <div className="fixed inset-0 bg-[#0c0c0e] text-white z-[100] flex flex-col font-sans overflow-hidden">
      <header className="p-4 border-b border-zinc-800 flex justify-between items-center bg-[#121214]">
        <div className="flex items-center gap-4">
            <h1 className="text-xl font-bold text-blue-500 uppercase tracking-widest">AIRender Studio</h1>
            <button onClick={onReauth} className="flex items-center gap-1.5 px-3 py-1 bg-zinc-800 hover:bg-zinc-700 rounded-full text-[10px] font-bold text-zinc-400 transition-colors">
                <KeyIcon /> Update API Key
            </button>
        </div>
        <div className="flex items-center gap-4">
          <span className="text-sm font-bold text-blue-400">{currentCredits} Credits</span>
          <button onClick={onClose} className="px-4 py-2 bg-zinc-800 rounded-lg text-sm font-bold hover:bg-zinc-700">Exit Studio</button>
        </div>
      </header>
      <div className="flex-grow flex overflow-hidden">
        <aside className="w-80 border-r border-zinc-800 p-6 flex flex-col gap-6 bg-[#0f0f11] overflow-y-auto">
          <div className="p-3 bg-amber-900/20 border border-amber-900/50 rounded-xl">
              <p className="text-[10px] text-amber-500 leading-tight font-medium">
                  <b>VEO Notice:</b> 영상 생성은 반드시 <b>유료 결제가 활성화된</b> 프로젝트의 API 키가 필요합니다. 오류 시 상단의 'Update API Key'를 눌러주세요.
              </p>
          </div>
          <div>
            <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest mb-3 block">Engine</label>
            <div className="flex bg-zinc-900 p-1 rounded-xl gap-1">
              <button onClick={() => setSelectedModel('veo-3.1-fast-generate-preview')} className={`flex-1 py-2 rounded-lg text-[10px] font-bold transition-all ${selectedModel.includes('fast') ? 'bg-blue-600' : 'text-zinc-500 hover:text-white'}`}>FAST (5C)</button>
              <button onClick={() => setSelectedModel('veo-3.1-generate-preview')} className={`flex-1 py-2 rounded-lg text-[10px] font-bold transition-all ${!selectedModel.includes('fast') ? 'bg-blue-600' : 'text-zinc-500 hover:text-white'}`}>PRO (15C)</button>
            </div>
          </div>
          <div>
            <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest mb-3 block">Mode</label>
            {['living', 'morph', 'multi'].map(m => (
              <button key={m} onClick={() => setMode(m as any)} className={`w-full p-3 rounded-xl mb-2 text-left text-xs font-bold transition-all ${mode === m ? 'bg-blue-600 text-white' : 'bg-zinc-900 text-zinc-500 hover:text-white'}`}>{m.toUpperCase()}</button>
            ))}
          </div>
          <textarea value={prompt} onChange={e => setPrompt(e.target.value)} placeholder="Describe camera motion or scene changes..." className="w-full h-32 bg-zinc-900 border border-zinc-800 rounded-xl p-4 text-sm outline-none resize-none focus:border-blue-500" />
          <button disabled={isGenerating || keyframes.length === 0} onClick={handleStartGeneration} className="mt-auto py-4 bg-blue-600 hover:bg-blue-700 disabled:bg-zinc-800 disabled:text-zinc-500 rounded-xl font-bold flex items-center justify-center gap-2 transition-all active:scale-95">
            {isGenerating ? <Spinner /> : <><PlayIcon /> Render Video</>}
          </button>
        </aside>
        <main className="flex-grow flex flex-col bg-[#080809] p-8 overflow-hidden relative">
          <div className="flex-grow flex items-center justify-center gap-6">
             {Array.from({ length: mode === 'multi' ? 3 : mode === 'morph' ? 2 : 1 }).map((_, i) => (
              <div key={i} className="flex flex-col items-center gap-3">
                <div className="w-80 aspect-video bg-zinc-900 border-2 border-dashed border-zinc-800 rounded-2xl flex items-center justify-center overflow-hidden relative group">
                  {keyframes[i] ? (
                      <>
                        <img src={keyframes[i].url} className="w-full h-full object-cover" />
                        <button onClick={() => setKeyframes(prev => prev.filter((_, idx) => idx !== i))} className="absolute top-2 right-2 p-1 bg-black/50 rounded-full opacity-0 group-hover:opacity-100 transition-opacity">
                            <CloseIcon />
                        </button>
                      </>
                  ) : <span className="text-zinc-700 text-xs font-bold uppercase">Frame {i+1}</span>}
                </div>
              </div>
            ))}
          </div>
          <div className="h-56 bg-[#121214] border-t border-zinc-800 p-6 overflow-x-auto flex gap-6 scrollbar-hide">
            {galleryImages.map((img, idx) => (
              <button key={idx} onClick={() => setKeyframes(prev => [...prev, { url: img.url, file: img.file! }].slice(0, mode === 'multi' ? 3 : mode === 'morph' ? 2 : 1))} className="flex-shrink-0 w-48 aspect-video rounded-xl overflow-hidden border-2 border-transparent hover:border-blue-500 transition-all shadow-lg active:scale-95">
                <img src={img.url} className="w-full h-full object-cover" />
              </button>
            ))}
          </div>
        </main>
        <aside className="w-80 border-l border-zinc-800 bg-[#0d0d0f] p-6 overflow-y-auto">
          <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest mb-4 block">Recent Recordings</label>
          <div className="flex flex-col gap-4">
            {activeJobs.map(job => (
              <div key={job.id} className="p-4 bg-zinc-900 rounded-2xl border border-zinc-800 hover:border-zinc-700 transition-all">
                <div className="flex justify-between items-center mb-3">
                  <span className={`text-[8px] font-black px-2 py-0.5 rounded uppercase ${job.status === 'done' ? 'bg-green-600' : job.status === 'error' ? 'bg-red-600' : 'bg-blue-600 animate-pulse'}`}>{job.status}</span>
                  <button onClick={() => deleteData('videos', job.id).then(() => setActiveJobs(p => p.filter(j => j.id !== job.id)))} className="text-zinc-600 hover:text-red-500 transition-colors"><TrashIcon /></button>
                </div>
                <div className="w-full aspect-video bg-black rounded-lg overflow-hidden flex items-center justify-center">
                  {job.videoUrl ? <video src={job.videoUrl} controls className="w-full h-full" /> : <div className="text-center p-4"><Spinner /><p className="text-[10px] text-zinc-500 mt-2">{job.progressMessage}</p></div>}
                </div>
