import { GoogleGenAI, GenerateContentResponse, VideoGenerationReferenceType } from "@google/genai";

export type EditParams = 
    | { type: 'point', points: { x: number; y: number }[] } 
    | { type: 'mask', maskImage: File }
    | { type: 'draw', annotationImage: File }
    | { type: 'facades', placements: { point: { x: number; y: number }, file: File }[], annotationImage?: File };

export interface ViewParams {
    cameraPoint?: { x: number, y: number }; 
    targetPoint?: { x: number, y: number }; 
    timeOfDay: number; 
    season: number; 
    people: number; 
    vegetation: number; 
    isPlanTo3D?: boolean;
    ceilingHeight?: number; 
}

export interface VideoGenerationParams {
  prompt: string;
  image?: File;
  lastFrame?: File;
  referenceImages?: File[]; 
  aspectRatio: '16:9' | '9:16';
  resolution: '720p' | '1080p';
  model: string;
}

const getSystemInstruction = (): string => {
    return localStorage.getItem('custom_system_prompt') || 'You are an expert architectural visualization AI.';
};

const fileToDataUrl = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.readAsDataURL(file);
        reader.onload = () => resolve(reader.result as string);
        reader.onerror = error => reject(error);
    });
};

const fileToBase64 = async (file: File): Promise<string> => {
    const dataUrl = await fileToDataUrl(file);
    return dataUrl.split(',')[1];
};

const fileToPart = async (file: File): Promise<{ inlineData: { mimeType: string; data: string; } }> => {
    const dataUrl = await fileToDataUrl(file);
    const arr = dataUrl.split(',');
    if (arr.length < 2) throw new Error("Invalid data URL");
    const mimeMatch = arr[0].match(/:(.*?);/);
    if (!mimeMatch || !mimeMatch[1]) throw new Error("Could not parse MIME type");
    const mimeType = mimeMatch[1];
    const data = arr[1];
    return { inlineData: { mimeType, data } };
};

const compositeAnnotations = async (baseFile: File, annotationFile: File): Promise<File> => {
    return new Promise((resolve, reject) => {
        const baseReader = new FileReader();
        baseReader.readAsDataURL(baseFile);
        baseReader.onload = () => {
            const baseImg = new Image();
            baseImg.src = baseReader.result as string;
            baseImg.onload = () => {
                const annReader = new FileReader();
                annReader.readAsDataURL(annotationFile);
                annReader.onload = () => {
                    const annImg = new Image();
                    annImg.src = annReader.result as string;
                    annImg.onload = () => {
                        const canvas = document.createElement('canvas');
                        canvas.width = baseImg.naturalWidth;
                        canvas.height = baseImg.naturalHeight;
                        const ctx = canvas.getContext('2d');
                        if (!ctx) return reject("Context error");
                        ctx.drawImage(baseImg, 0, 0);
                        ctx.drawImage(annImg, 0, 0, canvas.width, canvas.height);
                        canvas.toBlob(blob => {
                            if (blob) resolve(new File([blob], "annotated.jpg", { type: 'image/jpeg' }));
                            else reject("Blob error");
                        }, 'image/jpeg', 0.95);
                    };
                };
            };
        };
    });
};

const drawOnImage = async (
    sourceFile: File,
    points: { x: number; y: number }[],
    color: string = '#FF00FF',
    small: boolean = false,
    numbered: boolean = false,
    extraLayer?: File
): Promise<File> => {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.readAsDataURL(sourceFile);
        reader.onload = (event) => {
            if (!event.target?.result) return reject(new Error("Failed to read"));
            const img = new Image();
            img.src = event.target.result as string;
            img.onload = async () => {
                const canvas = document.createElement('canvas');
                canvas.width = img.naturalWidth;
                canvas.height = img.naturalHeight;
                const ctx = canvas.getContext('2d');
                if (!ctx) return reject(new Error('Context failed'));
                ctx.drawImage(img, 0, 0);

                if (extraLayer) {
                    const extraImg = new Image();
                    extraImg.src = URL.createObjectURL(extraLayer);
                    await new Promise(res => { extraImg.onload = () => { ctx.drawImage(extraImg, 0, 0, canvas.width, canvas.height); res(null); } });
                }

                points.forEach((p, i) => {
                    ctx.fillStyle = color;
                    ctx.strokeStyle = 'white';
                    let markerRadius = Math.max(12, Math.min(canvas.width, canvas.height) * 0.012);
                    if (small) markerRadius *= 0.6;

                    ctx.beginPath();
                    ctx.arc(p.x, p.y, markerRadius, 0, 2 * Math.PI, false);
                    ctx.fill();
                    ctx.lineWidth = markerRadius * 0.2;
                    ctx.stroke();

                    if (numbered) {
                        ctx.fillStyle = 'white';
                        ctx.font = `bold ${Math.round(markerRadius * 1.2)}px Inter, sans-serif`;
                        ctx.textAlign = 'center';
                        ctx.textBaseline = 'middle';
                        ctx.fillText((i + 1).toString(), p.x, p.y);
                    }
                });

                canvas.toBlob((blob) => {
                    if (blob) resolve(new File([blob], `marked-${sourceFile.name}`, { type: 'image/jpeg' }));
                    else reject(new Error('Blob failed'));
                }, 'image/jpeg', 0.95);
            };
        };
    });
};

export const resizeImage = (file: File, maxDimension: number = 1024): Promise<File> => {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.readAsDataURL(file);
        reader.onload = (event) => {
            const img = new Image();
            img.src = event.target?.result as string;
            img.onload = () => {
                const canvas = document.createElement('canvas');
                let { width, height } = img;
                if (width > height) { if (width > maxDimension) { height = Math.round(height * (maxDimension / width)); width = maxDimension; } }
                else { if (height > maxDimension) { width = Math.round(width * (maxDimension / height)); height = maxDimension; } }
                canvas.width = width; canvas.height = height;
                const ctx = canvas.getContext('2d');
                if (!ctx) return reject(new Error('Canvas failed'));
                ctx.drawImage(img, 0, 0, width, height);
                canvas.toBlob((blob) => {
                    if (blob) resolve(new File([blob], file.name, { type: 'image/jpeg' }));
                    else reject(new Error('Blob failed'));
                }, 'image/jpeg', 0.9);
            };
        };
    });
};

export const prepareExpandImage = async (file: File, ratio: 'wide' | 'tall' | 'square' | 'out'): Promise<{ paddedImage: File; maskImage: File }> => {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.readAsDataURL(file);
        reader.onload = (e) => {
            const img = new Image();
            img.src = e.target?.result as string;
            img.onload = () => {
                let targetWidth = img.naturalWidth;
                let targetHeight = img.naturalHeight;
                if (ratio === 'wide') targetWidth = Math.round(img.naturalHeight * (16 / 9));
                else if (ratio === 'tall') targetHeight = Math.round(img.naturalWidth * (16 / 9));
                else if (ratio === 'square') { const side = Math.max(img.naturalWidth, img.naturalHeight); targetWidth = side; targetHeight = side; }
                else if (ratio === 'out') { targetWidth = Math.round(img.naturalWidth * 1.5); targetHeight = Math.round(img.naturalHeight * 1.5); }
                targetWidth = Math.max(targetWidth, img.naturalWidth);
                targetHeight = Math.max(targetHeight, img.naturalHeight);
                const canvas = document.createElement('canvas');
                canvas.width = targetWidth; canvas.height = targetHeight;
                const ctx = canvas.getContext('2d');
                if (!ctx) return reject(new Error("Context failed"));
                ctx.fillStyle = "#FF0000"; ctx.fillRect(0, 0, targetWidth, targetHeight);
                const offsetX = (targetWidth - img.naturalWidth) / 2;
                const offsetY = (targetHeight - img.naturalHeight) / 2;
                ctx.drawImage(img, offsetX, offsetY);
                const maskCanvas = document.createElement('canvas');
                maskCanvas.width = targetWidth; maskCanvas.height = targetHeight;
                const mCtx = maskCanvas.getContext('2d');
                if (!mCtx) return reject(new Error("Mask failed"));
                mCtx.fillStyle = "#FFFFFF"; mCtx.fillRect(0, 0, targetWidth, targetHeight);
                const overlap = Math.min(img.naturalWidth, img.naturalHeight) * 0.05; 
                mCtx.fillStyle = "#000000"; mCtx.fillRect(offsetX + overlap, offsetY + overlap, img.naturalWidth - (overlap * 2), img.naturalHeight - (overlap * 2));
                canvas.toBlob((paddedBlob) => {
                    maskCanvas.toBlob((maskBlob) => {
                        if (paddedBlob && maskBlob) resolve({ paddedImage: new File([paddedBlob], "padded.jpg", { type: "image/jpeg" }), maskImage: new File([maskBlob], "mask.png", { type: "image/png" }) });
                        else reject(new Error("Blob failed"));
                    }, "image/png");
                }, "image/jpeg", 0.95);
            };
        };
    });
};

const getPosName = (x: number, y: number): string => {
    let horizontal = x < 0.33 ? 'left' : x < 0.66 ? 'center' : 'right';
    let vertical = y < 0.33 ? 'top' : y < 0.66 ? 'middle' : 'bottom';
    return `${vertical}-${horizontal}`;
};

export const getViewPrompt = (params: ViewParams): string => {
    let prompt = "";
    if (params.isPlanTo3D) {
        prompt += `SOURCE CONTEXT: This is a 2D floor plan. Transform this into a realistic 3D architectural perspective. Ceiling height: ${params.ceilingHeight || 2.7}m. `;
    }

    if (params.cameraPoint && params.targetPoint) {
        const deltaY = params.targetPoint.y - params.cameraPoint.y;
        if (deltaY < -0.1) prompt += "Low angle view. ";
        else if (deltaY > 0.1) prompt += "Aerial view. ";
        else prompt += "Eye-level perspective. ";

        const camPos = getPosName(params.cameraPoint.x, params.cameraPoint.y);
        const tarPos = getPosName(params.targetPoint.x, params.targetPoint.y);

        if (params.isPlanTo3D) {
            prompt += `Position observer at ${camPos}, looking towards ${tarPos}. `;
        }
    }

    switch (params.timeOfDay) {
        case 6: prompt += "Dawn. "; break;
        case 9: prompt += "Morning. "; break;
        case 12: prompt += "Noon. "; break;
        case 15: prompt += "Afternoon. "; break;
        case 18: prompt += "Sunset. "; break;
        case 21: prompt += "Night. "; break;
    }

    const seasons = ["Spring", "Summer", "Autumn", "Winter"];
    prompt += `${seasons[params.season] || ""} season. `;

    if (params.people <= 0.1) prompt += "Empty scene. ";
    else if (params.people <= 0.5) prompt += "Few people. ";
    else prompt += "Lively atmosphere. ";

    if (params.vegetation <= 0.1) prompt += "Minimal plants. ";
    else if (params.vegetation <= 0.5) prompt += "Balanced landscaping. ";
    else prompt += "Lush greenery. ";

    return prompt;
};

export const generateArchitecturalImage = async (
    baseImage: File,
    prompt: string,
    editParams: EditParams | null,
    referenceImage: File | null,
    influenceStrength: number,
    modelName: string,
    imageResolution: string = '1K',
    viewParams?: ViewParams,
    objectImage: File | null = null,
): Promise<{ imageUrl: string; }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const systemInstruction = getSystemInstruction();
  const model = modelName;
  const parts: ( { text: string } | { inlineData: { mimeType: string; data:string; } } )[] = [];
  let finalPrompt = '';

  if (viewParams) {
     const viewDescription = getViewPrompt(viewParams);
     finalPrompt = `**TASK: ARCHITECTURAL RE-RENDERING**\n${viewDescription}\nAdditional instruction: ${prompt}`;
     parts.push(await fileToPart(baseImage));
     parts.push({ text: finalPrompt });
  }
  else if (editParams?.type === 'facades' && editParams.placements.length > 0) {
      const placementPoints = editParams.placements.map(p => p.point);
      const markedBase = await drawOnImage(baseImage, placementPoints, '#FF00FF', true, true, editParams.annotationImage);
      parts.push(await fileToPart(markedBase));

      let mappingInstructions = "";
      for(let i=0; i < editParams.placements.length; i++) {
          const placement = editParams.placements[i];
          parts.push(await fileToPart(placement.file));
          mappingInstructions += `- MAGENTA DOT #${i+1}: Apply pattern from Image #${i+2}.\n`;
      }

      finalPrompt = `**TASK: FACADE COLLAGE**
      1. Use Image 1 as master perspective.
      2. Interpret annotations as design constraints.
      3. REFERENCE MAPPING: ${mappingInstructions}
      4. ERASE markers and labels in final render.
      Design Intent: ${prompt || "Photorealistic finish."}`;
      parts.push({ text: finalPrompt });
  }
  else if (objectImage) {
      let imageToSend = baseImage;
      if (editParams?.type === 'point' && editParams.points.length > 0) {
          imageToSend = await drawOnImage(baseImage, editParams.points, '#EAB308', true); 
      }
      parts.push(await fileToPart(imageToSend));
      parts.push(await fileToPart(objectImage));
      finalPrompt = `**TASK: OBJECT INSERTION**
      Insert object from 2nd image into 1st image at YELLOW DOT.
      Erase yellow marker. Blend lighting/perspective.
      Instruction: ${prompt || "Place naturally."}`;
      parts.push({ text: finalPrompt });
  }
  else if (editParams?.type === 'draw') {
      const guideImage = await compositeAnnotations(baseImage, editParams.annotationImage);
      parts.push(await fileToPart(guideImage));
      finalPrompt = `**TASK: ANNOTATED RENDERING**
      Re-render base scene interpreting red sketches/text as design intent.
      Erase all annotations.
      Instruction: ${prompt || "Render changes."}`;
      parts.push({ text: finalPrompt });
  }
  else if (referenceImage) {
    const strengthText = influenceStrength <= 0.3 ? "Subtle" : influenceStrength <= 0.7 ? "Balanced" : "Strong";
    if (editParams?.type === 'mask') {
        finalPrompt = `**TASK: MASKED STYLE TRANSFER**\nInfluence: ${strengthText}\nInstruction: ${prompt}`;
        parts.push(await fileToPart(baseImage));
        parts.push(await fileToPart(referenceImage));
        parts.push(await fileToPart(editParams.maskImage));
        parts.push({ text: finalPrompt });
    } else if (editParams?.type === 'point' && editParams.points.length > 0) {
        const imageToSend = await drawOnImage(baseImage, editParams.points, 'red', true);
        parts.push(await fileToPart(imageToSend));
        parts.push(await fileToPart(referenceImage));
        finalPrompt = `**TASK: POINT STYLE TRANSFER**\nStyle Strength: ${strengthText}\nInstruction: ${prompt}`;
        parts.push({ text: finalPrompt });
    } else {
        finalPrompt = `**TASK: STYLE TRANSFER**\nStrength: ${strengthText}\nInstruction: ${prompt}`;
        parts.push(await fileToPart(baseImage));
        parts.push(await fileToPart(referenceImage));
        parts.push({ text: finalPrompt });
    }
  }
  else if (editParams?.type === 'mask') {
      finalPrompt = `**TASK: MASKED EDIT**\nChange ONLY white mask area.\nInstruction: ${prompt}`;
      parts.push(await fileToPart(baseImage));
      parts.push(await fileToPart(editParams.maskImage));
      parts.push({ text: finalPrompt });
  } else if (editParams?.type === 'point' && editParams.points.length > 0) {
      const imageToSend = await drawOnImage(baseImage, editParams.points, 'red', true);
      parts.push(await fileToPart(imageToSend));
      finalPrompt = `**TASK: POINT EDIT**\nFocus at red marker.\nInstruction: ${prompt}`;
      parts.push({ text: finalPrompt });
  }
  else {
      finalPrompt = `**TASK: TRANSFORMATION**\nInstruction: ${prompt}`;
      parts.push(await fileToPart(baseImage));
      parts.push({ text: finalPrompt });
  }

  const generateConfig: any = {
    systemInstruction: systemInstruction,
  };
  if (model === 'gemini-3-pro-image-preview') {
      generateConfig.imageConfig = { imageSize: imageResolution };
  }

  const response: GenerateContentResponse = await ai.models.generateContent({ model, contents: { parts }, config: generateConfig });

  if (response.text && !response.candidates?.[0]?.content?.parts?.some(p => p.inlineData)) {
      throw new Error(`Model returned text instead of image: ${response.text}`);
  }

  const imagePartFromResponse = response.candidates?.[0]?.content?.parts?.find(part => part.inlineData);
  if (imagePartFromResponse?.inlineData) {
    const { mimeType, data } = imagePartFromResponse.inlineData;
    return { imageUrl: `data:${mimeType};base64,${data}` };
  }

  throw new Error("No image generated. Please try a different prompt or check settings.");
};

export const generateMoodboardImage = async (imageFiles: File[]): Promise<string> => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const model = 'gemini-3-pro-image-preview';
    const imageParts = await Promise.all(imageFiles.map(file => fileToPart(file)));
    const prompt = `Synthesize these into a single representative moodboard.`;
    const response: GenerateContentResponse = await ai.models.generateContent({ 
        model, 
        contents: { parts: [...imageParts, { text: prompt }] }, 
        config: { systemInstruction: getSystemInstruction() }, 
    });
    const imagePartFromResponse = response.candidates?.[0]?.content?.parts?.find(part => part.inlineData);
    if (imagePartFromResponse?.inlineData) {
        const { mimeType, data } = imagePartFromResponse.inlineData;
        return `data:${mimeType};base64,${data}`;
    }
    throw new Error("Moodboard failed.");
};

export const removeBackground = async (imageFile: File): Promise<string> => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const model = 'gemini-3-pro-image-preview';
    const imagePart = await fileToPart(imageFile);
    const prompt = `Segment subject on pure white background (#FFFFFF). Clean edges.`;
    const response: GenerateContentResponse = await ai.models.generateContent({ 
        model, 
        contents: { parts: [imagePart, { text: prompt }] }, 
        config: { systemInstruction: "Object extraction expert." }, 
    });
    const imagePartFromResponse = response.candidates?.[0]?.content?.parts?.find(part => part.inlineData);
    if (imagePartFromResponse?.inlineData) {
        const { mimeType, data } = imagePartFromResponse.inlineData;
        return `data:${mimeType};base64,${data}`;
    }
    throw new Error("BG removal failed.");
};

export const startVideoGeneration = async (params: VideoGenerationParams) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const config: any = {
    numberOfVideos: 1,
    resolution: params.resolution,
    aspectRatio: params.aspectRatio,
  };

  const model = params.model;

  if (params.referenceImages && params.referenceImages.length > 0) {
      const refPayload = await Promise.all(params.referenceImages.map(async (file) => ({
          image: {
              imageBytes: await fileToBase64(file),
              mimeType: file.type
          },
          referenceType: VideoGenerationReferenceType.ASSET
      })));

      return await ai.models.generateVideos({
          model: model,
          prompt: params.prompt,
          config: {
              ...config,
              referenceImages: refPayload
          }
      });
  }

  const imageBase64 = params.image ? await fileToBase64(params.image) : undefined;
  const lastFrameBase64 = params.lastFrame ? await fileToBase64(params.lastFrame) : undefined;

  return await ai.models.generateVideos({
    model: model,
    prompt: params.prompt,
    image: imageBase64 ? {
      imageBytes: imageBase64,
      mimeType: params.image!.type,
    } : undefined,
    config: {
      ...config,
      lastFrame: lastFrameBase64 ? {
        imageBytes: lastFrameBase64,
        mimeType: params.lastFrame!.type,
      } : undefined,
    }
  });
};

export const checkVideoStatus = async (operation: any) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  return await ai.operations.getVideosOperation({ operation });
};

