// Fix: Add export keyword to allow named or default export
export const App: React.FC = () => {
    // Auth & User State
    const [user, setUser] = useState<any>(null); 
    const [credits, setCredits] = useState<number>(0);
    const [authLoading, setAuthLoading] = useState(true);
    const [showAdminPass, setShowAdminPass] = useState(false);
    const [adminPassword, setAdminPassword] = useState('');
    const [adminBtnClicks, setAdminBtnClicks] = useState(0);

    // Image State
    const [originalImage, setOriginalImage] = useState<HistoryItem | null>(null);
    const [currentImage, setCurrentImage] = useState<HistoryItem | null>(null);
    const [imageHistory, setImageHistory] = useState<HistoryItem[]>([]);
    const [referenceImage, setReferenceImage] = useState<HistoryItem | null>(null);
    const [objectImage, setObjectImage] = useState<HistoryItem | null>(null);
    const [imageToCrop, setImageToCrop] = useState<HistoryItem | null>(null);

    // Facade collage state
    const [placedFacades, setPlacedFacades] = useState<PlacedFacade[]>([]);
    const [selectedFacadeForPlacing, setSelectedFacadeForPlacing] = useState<any | null>(null);
    const [facadeLibraryItems, setFacadeLibraryItems] = useState<any[]>([]);
    const facadeFileInputRef = useRef<HTMLInputElement>(null);

    // Zoom state
    const [zoom, setZoom] = useState(1);
    const [pan, setPan] = useState({ x: 0, y: 0 });
    const [isPanning, setIsPanning] = useState(false);
    const panStartRef = useRef({ x: 0, y: 0 });

    // UI & Generation State
    const [userInput, setUserInput] = useState<string>('');
    const [activeRequests, setActiveRequests] = useState<number>(0);
    const [isCropping, setIsCropping] = useState<boolean>(false);
    const [isDownloadingAll, setIsDownloadingAll] = useState<boolean>(false);
    const [error, setError] = useState<string | null>(null);
    const [activeTab, setActiveTab] = useState<Tab>('upload');
    const [isComparing, setIsComparing] = useState<boolean>(false);

    // Strengths
    const [promptStrength, setPromptStrength] = useState(0.5);
    const [styleStrength, setStyleStrength] = useState(0.5);
    const [view, setView] = useState<View>('main');

    // Model Config
    const [selectedModel, setSelectedModel] = useState<string>('gemini-2.5-flash-image');
    const [imageResolution, setImageResolution] = useState<string>('1K');

    // Tools State
    const [editTool, setEditTool] = useState<EditTool>('area'); 
    const [drawMode, setDrawMode] = useState<DrawMode>('pen');
    const [strokeColor, setStrokeColor] = useState<string>('#EF4444');
    const [strokeWidth, setStrokeWidth] = useState<number>(4);
    const [editPoint, setEditPoint] = useState<{ x: number; y: number } | null>(null);
    const [referencePoint, setReferencePoint] = useState<{ x: number; y: number } | null>(null);
    const [placementPoint, setPlacementPoint] = useState<{ x: number; y: number } | null>(null);
    const [areaShape, setAreaShape] = useState<AreaShape>('point'); 
    const [expandRatio, setExpandRatio] = useState<ExpandRatio>('wide');

    // View Tool Settings (Camera)
    const [viewTool, setViewTool] = useState<ViewTool | null>(null);
    const [cameraPosition, setCameraPosition] = useState<{ x: number; y: number } | null>(null);
    const [targetPosition, setTargetPosition] = useState<{ x: number; y: number } | null>(null);
    const [isPlanTo3D, setIsPlanTo3D] = useState<boolean>(false);
    const [ceilingHeight, setCeilingHeight] = useState<number>(2.7);

    // Unified View/Environment Settings
    const [isEditSlidersEnabled, setIsEditSlidersEnabled] = useState<boolean>(false);
    const [viewSettings, setViewSettings] = useState<ViewParams>({
        timeOfDay: 12,
        season: 1,
        people: 0.1,
        vegetation: 0.5,
        isPlanTo3D: false,
        ceilingHeight: 2.7
    });

    const [hasApiKey, setHasApiKey] = useState<boolean>(false);
    const [apiKeyCheckLoading, setApiKeyCheckLoading] = useState<boolean>(true);
    const [isStoreOpen, setIsStoreOpen] = useState(false);

    const imageContainerRef = useRef<HTMLDivElement>(null);
    const maskCanvasRef = useRef<PolygonMaskCanvasRef>(null);
    const annotationCanvasRef = useRef<AnnotationCanvasRef>(null);
    const cropperRef = useRef<ImageCropperRef>(null);
    const inputRef = useRef<HTMLTextAreaElement>(null);

    // Cost calculation memoized for performance
    const generationCost = useMemo(() => {
        let cost = 1; 
        if (selectedModel === 'gemini-3-pro-image-preview') cost = 3;
        if (imageResolution === '2K') cost += 2; 
        if (imageResolution === '4K') cost += 5;
        if (editTool === 'expand') cost += 1; 
        if (editTool === 'object') cost += 1; 
        if (editTool === 'draw') cost += 1;
        if (editTool === 'facade') cost += 2;
        return cost;
    }, [selectedModel, imageResolution, editTool]);

    useEffect(() => {
        if (selectedModel === 'gemini-2.5-flash-image' && imageResolution !== '1K') { setImageResolution('1K'); }
    }, [selectedModel, imageResolution]);

    useEffect(() => { setZoom(1); setPan({ x: 0, y: 0 }); }, [currentImage?.id, isComparing]);

    useEffect(() => {
        const unsubscribe = onAuthStateChanged(auth, async (currentUser) => {
            if (currentUser) {
                setUser(currentUser);
                const creditCount = await getUserCredits(currentUser.uid);
                setCredits(creditCount);
                // Load facades
                const facades = await getAllData('facades', currentUser.uid);
                setFacadeLibraryItems(facades);
            } else if (user?.uid !== 'admin') { setUser(null); setCredits(0); }
            setAuthLoading(false);
        });
        return () => unsubscribe();
    }, [user?.uid]);

    const checkApiKeyStatus = useCallback(async () => {
        if ((window as any).aistudio) { 
            const hasKey = await (window as any).aistudio.hasSelectedApiKey(); 
            setHasApiKey(hasKey); 
            return hasKey;
        } 
        setHasApiKey(true);
        return true;
    }, []);

    useEffect(() => {
        const checkKey = async () => {
             await checkApiKeyStatus();
             setApiKeyCheckLoading(false);
        }
        checkKey();
    }, [checkApiKeyStatus]);

    useEffect(() => {
        const handlePaste = (event: ClipboardEvent) => {
            if (event.target instanceof HTMLInputElement || event.target instanceof HTMLTextAreaElement) return;
            const items = event.clipboardData?.items; if (!items) return;
            const imageItem = Array.from(items).find(item => item.type.startsWith('image/'));
            if (imageItem) {
                const file = imageItem.getAsFile();
                if (file) {
                    event.preventDefault();
                    if (activeTab === 'edit' && editTool === 'style') handleReferenceImageUpload(file);
                    else if (activeTab === 'edit' && editTool === 'object') handleObjectImageUpload(file);
                    else handleInitialImageSelect(file);
                }
            }
        };
        window.addEventListener('paste', handlePaste);
        return () => window.removeEventListener('paste', handlePaste);
    }, [activeTab, editTool]);

    useEffect(() => {
        if (activeTab !== 'edit') {
            setEditPoint(null); setReferencePoint(null); setViewTool(null); setPlacementPoint(null);
            setCameraPosition(null); setTargetPosition(null); setPlacedFacades([]);
        } else {
            if (editTool !== 'area' || (editTool === 'area' && areaShape !== 'point')) setEditPoint(null);
            if (editTool !== 'style') setReferencePoint(null);
            if (editTool !== 'object') setPlacementPoint(null);
            if (editTool !== 'facade') {
                setPlacedFacades([]);
                setDrawMode('pen');
            } else {
                setDrawMode('marker');
            }
            if (editTool !== 'camera') { setViewTool(null); setCameraPosition(null); setTargetPosition(null); }
            if (editTool !== 'area') maskCanvasRef.current?.clearMask();
            if (editTool !== 'draw' && editTool !== 'facade') annotationCanvasRef.current?.clearAnnotations();
        }
    }, [activeTab, editTool, areaShape]);

    const handleInputResize = () => {
        if (inputRef.current) { inputRef.current.style.height = 'auto'; inputRef.current.style.height = `${Math.min(inputRef.current.scrollHeight, 150)}px`; }
    };
    useEffect(() => { handleInputResize(); }, [userInput]);

    const handleWheel = (e: React.WheelEvent) => {
        if (isComparing || (editTool === 'draw' && drawMode !== 'marker') || (editTool === 'facade' && drawMode !== 'marker')) return;
        const delta = e.deltaY * -0.001;
        const newZoom = Math.min(Math.max(1, zoom + delta), 5);
        setZoom(newZoom);
    };

    const handlePanStart = (e: React.MouseEvent | React.TouchEvent) => {
        if (zoom <= 1 || isComparing || (editTool === 'draw' && drawMode !== 'marker') || (editTool === 'facade' && drawMode !== 'marker')) return;
        setIsPanning(true);
        const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
        const clientY = 'touches' in e ? e.touches[0].clientY : e.clientY;
        panStartRef.current = { x: clientX - pan.x, y: clientY - pan.y };
    };

    const handlePanMove = (e: React.MouseEvent | React.TouchEvent) => {
        if (!isPanning || zoom <= 1 || isComparing || (editTool === 'draw' && drawMode !== 'marker') || (editTool === 'facade' && drawMode !== 'marker')) return;
        const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
        const clientY = 'touches' in e ? e.touches[0].clientY : e.clientY;
        setPan({ x: clientX - panStartRef.current.x, y: clientY - panStartRef.current.y });
    };

    const handlePanEnd = () => setIsPanning(false);

    const handleSelectKey = async () => {
        try { if ((window as any).aistudio) { await (window as any).aistudio.openSelectKey(); setHasApiKey(true); } } 
        catch (e: any) { if (e.message?.includes("Requested entity was not found")) { setHasApiKey(false); alert("API Key not found or invalid."); } }
    };

    const handleLogin = async () => { try { await signInWithGoogle(); } catch (error) { alert("Login failed."); } };
    const handleAdminLogin = async () => {
        if (adminPassword === '1901') {
            setUser({ uid: 'admin', email: 'admin@local', displayName: 'System Admin', photoURL: null });
            setCredits(await getUserCredits('admin'));
            setAdminPassword(''); setShowAdminPass(false); setAdminBtnClicks(0);
        } else { alert("Incorrect password."); }
    };
    const handleAdminBtnClick = () => { const nextCount = adminBtnClicks + 1; if (nextCount >= 5) { setShowAdminPass(true); setAdminBtnClicks(0); } else { setAdminBtnClicks(nextCount); } }
    const handleLogout = async () => { if (user?.uid === 'admin') { setUser(null); setCredits(0); } else await signOut(); };
    const handleChargeCredits = () => setIsStoreOpen(true);
    const handlePurchaseCredits = async (amount: number) => {
        if (!user) return;
        try { await chargeCredits(user.uid, amount); setCredits(await getUserCredits(user.uid)); setIsStoreOpen(false); alert(`Successfully purchased ${amount} credits!`); } 
        catch (error) { alert("Failed to process purchase."); }
    };

    const handleInitialImageSelect = useCallback((file: File) => {
        if (imageToCrop) URL.revokeObjectURL(imageToCrop.url);
        const url = URL.createObjectURL(file);
        setImageToCrop({ file, url, status: 'complete', id: 'crop-preview' });
        setActiveTab('upload');
    }, [imageToCrop]);

    const saveToGallery = async (item: HistoryItem) => {
        if (!item.file || !user) return;
        try { const thumbnailFile = await resizeImage(item.file, 300); await addData('gallery', { id: Date.now(), file: item.file, thumbnailFile: thumbnailFile, prompt: item.prompt || 'Generated Image', userId: user.uid }); } 
        catch (error) { console.error('Error auto-saving image:', error); }
    };

    const processAndSetFinalImage = useCallback(async (file: File) => {
        setActiveRequests(prev => prev + 1); setError(null);
        try {
            const resizedFile = await resizeImage(file); const imageUrl = URL.createObjectURL(resizedFile);
            const newImage: HistoryItem = { id: `original-${Date.now()}`, file: resizedFile, url: imageUrl, prompt: 'Original', status: 'complete' };
            setOriginalImage(newImage); setCurrentImage(newImage); setImageHistory([newImage]);
            await saveToGallery(newImage); handleClearSelection();
            setActiveTab('edit'); setEditTool('area'); setAreaShape('point');
        } catch (e) { setError(`Could not process image: ${e instanceof Error ? e.message : 'Unknown error.'}`); } 
        finally { setActiveRequests(prev => prev - 1); }
    }, [user]);

    const handleSelectMoodboard = (dataUrl: string) => {
        const file = dataURLtoFile(dataUrl, `moodboard-${Date.now()}.png`);
        const newReferenceImage: HistoryItem = { id: `ref-${Date.now()}`, file, url: URL.createObjectURL(file), status: 'complete' };
        if (referenceImage) URL.revokeObjectURL(referenceImage.url); setReferenceImage(newReferenceImage);
        setView('main'); setActiveTab('edit'); setEditTool('style');
    };

    const handleSelectAsset = (dataUrl: string) => {
        const file = dataURLtoFile(dataUrl, `asset-${Date.now()}.png`);
        const newObjectImage: HistoryItem = { id: `obj-${Date.now()}`, file, url: URL.createObjectURL(file), status: 'complete' };
        if (objectImage) URL.revokeObjectURL(objectImage.url); setObjectImage(newObjectImage);
        setView('main'); setActiveTab('edit'); setEditTool('object');
    }

    const handleSelectFacade = async (item: any) => {
        setSelectedFacadeForPlacing(item);
        setView('main'); setActiveTab('edit'); setEditTool('facade');
        setDrawMode('marker'); 
        const facades = await getAllData('facades', user.uid);
        setFacadeLibraryItems(facades);
    }

    const handleQuickAddFacade = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const files = e.target.files;
        if (!files || !user) return;
        setActiveRequests(prev => prev + 1);
        try {
            const fileList = Array.from(files) as File[];
            for (const f of fileList) {
                const resized = await resizeImage(f, 512);
                const tempItem = {
                    id: `temp-${Date.now()}-${Math.random()}`,
                    url: URL.createObjectURL(resized),
                    name: f.name.split('.')[0],
                    file: resized
                };
                setFacadeLibraryItems(prev => [tempItem, ...prev]);
                if (!selectedFacadeForPlacing) {
                    setSelectedFacadeForPlacing(tempItem);
                    setDrawMode('marker');
                }
            }
        } finally {
            setActiveRequests(prev => prev - 1);
            if (e.target) e.target.value = '';
        }
    }

    const handleReferenceImageUpload = async (file: File) => {
        setActiveRequests(prev => prev + 1); setError(null);
        try { const resizedFile = await resizeImage(file); const newReferenceImage: HistoryItem = { id: `ref-${Date.now()}`, file: resizedFile, url: URL.createObjectURL(resizedFile), status: 'complete' }; if (referenceImage) URL.revokeObjectURL(referenceImage.url); setReferenceImage(newReferenceImage); } 
        catch (e) { setError(`Could not process reference image.`); } finally { setActiveRequests(prev => prev - 1); }
    };

    const handleRemoveReferenceImage = () => { if (referenceImage) { URL.revokeObjectURL(referenceImage.url); setReferenceImage(null); setReferencePoint(null); } };
    const handleObjectImageUpload = async (file: File) => {
        setActiveRequests(prev => prev + 1); setError(null);
        try { const resizedFile = await resizeImage(file); const newObjectImage: HistoryItem = { id: `obj-${Date.now()}`, file: resizedFile, url: URL.createObjectURL(resizedFile), status: 'complete' }; if (objectImage) URL.revokeObjectURL(objectImage.url); setObjectImage(newObjectImage); } 
        catch (e) { setError(`Could not process object image.`); } finally { setActiveRequests(prev => prev - 1); }
    }
    const handleRemoveObjectImage = () => { if (objectImage) { URL.revokeObjectURL(objectImage.url); setObjectImage(null); setPlacementPoint(null); } }

    const handleUseAsReference = async (item: { id: number, objectUrl: string }) => {
        setActiveRequests(prev => prev + 1);
        try {
            const response = await fetch(item.objectUrl); const blob = await response.blob();
            const file = new File([blob], `ref-${item.id}.png`, { type: blob.type }); const resizedFile = await resizeImage(file);
            const newReferenceImage: HistoryItem = { id: `ref-${Date.now()}`, file: resizedFile, url: URL.createObjectURL(resizedFile), status: 'complete' };
            if (referenceImage) URL.revokeObjectURL(referenceImage.url); setReferenceImage(newReferenceImage);
            setView('main'); setActiveTab('edit'); setEditTool('style');
        } catch (e) { alert("Could not load image as reference."); } finally { setActiveRequests(prev => prev - 1); }
    };

    const handleImageClick = async (e: React.MouseEvent<HTMLDivElement>) => {
